void deduplicate(vector<int>& nums)
{
    bitset<1000000> seen;
    vector<int> result;
    
    for (int x : nums)
    {
        if (!seen.test(x))
        {
            seen.set(x);
            result.push_back(x);
        }
    }
    
    nums.swap(result);
}
