## 一、基本用法

### 1.1 最大堆（默认）

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;
signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 默认是最大堆
    priority_queue<int> pq;
    
    // 插入元素
    pq.push(3);
    pq.push(1);
    pq.push(4);
    pq.push(1);
    pq.push(5);
    
    // 访问堆顶（最大元素）
    cout << "堆顶: " << pq.top() << endl;  // 5
    
    // 删除堆顶
    pq.pop();
    cout << "删除后堆顶: " << pq.top() << endl;  // 4
    
    // 遍历（会破坏堆结构）
    while (!pq.empty())
    {
        cout << pq.top() << " ";
        pq.pop();
    }
    // 输出: 4 3 1 1
    
    return 0;
}
