## 三、竞赛实战应用

### 3.1 Dijkstra 算法（最短路径）

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;

using ll = long long;
using pii = pair<ll, int>;  // (距离, 节点)

const ll INF = 1e18;

vector<ll> dijkstra(int start, const vector<vector<pii>>& g)
{
    int n = g.size();
    vector<ll> dist(n, INF);
    dist[start] = 0;
    
    // 最小堆，按距离排序
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    pq.emplace(0, start);
    
    while (!pq.empty())
    {
        pair<ll, int> top = pq.top();
        ll d = top.first;
        int u = top.second;
        pq.pop();
        
        if (d > dist[u])
        {
            continue;  // 旧的路径，跳过
        }
        
        for (const auto& edge : g[u])
        {
            int v = edge.first;
            ll w = edge.second;
            if (dist[v] > dist[u] + w)
            {
                dist[v] = dist[u] + w;
                pq.emplace(dist[v], v);
            }
        }
    }
    
    return dist;
}

signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m, start;
    cin >> n >> m >> start;
    
    vector<vector<pii>> g(n);
    for (int i = 0; i < m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        g[u].emplace_back(v, w);
    }
    
    vector<ll> dist = dijkstra(start, g);
    for (int i = 0; i < n; i++)
    {
        if (dist[i] == INF)
        {
            cout << "INF ";
        }
        else
        {
            cout << dist[i] << " ";
        }
    }
    
    return 0;
}
```

### 3.2 贪心算法

```cpp
// 活动选择问题（最大不重叠区间）
struct Interval
{
    int start, end;
    bool operator<(const Interval& other) const
    {
        return end > other.end;  // 按结束时间排序（最小堆）
    }
};

int max_non_overlapping(vector<Interval>& intervals)
{
    sort(intervals.begin(), intervals.end(), [](const Interval& a, const Interval& b)
    {
        return a.start < b.start;
    });
    
    priority_queue<Interval> pq;
    int count = 0;
    
    for (const auto& interval : intervals)
    {
        while (!pq.empty() && pq.top().end <= interval.start)
        {
            pq.pop();
        }
        pq.push(interval);
        count = max(count, (int)pq.size());
    }
    
    return count;
}

// 合并 k 个有序链表
struct ListNode
{
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

struct CompareNode
{
    bool operator()(ListNode* a, ListNode* b)
    {
        return a->val > b->val;  // 最小堆
    }
};

ListNode* merge_k_lists(vector<ListNode*>& lists)
{
    priority_queue<ListNode*, vector<ListNode*>, CompareNode> pq;
    
    for (ListNode* node : lists)
    {
        if (node)
        {
            pq.push(node);
        }
    }
    
    ListNode dummy(0);
    ListNode* tail = &dummy;
    
    while (!pq.empty())
    {
        ListNode* node = pq.top();
        pq.pop();
        
        tail->next = node;
        tail = tail->next;
        
        if (node->next)
        {
            pq.push(node->next);
        }
    }
    
    return dummy.next;
}
```

### 3.3 滑动窗口最大值

```cpp
vector<int> max_sliding_window(vector<int>& nums, int k)
{
    vector<int> res;
    // 最大堆，存储 (值, 索引)
    priority_queue<pair<int, int>> pq;
    
    for (int i = 0; i < nums.size(); i++)
    {
        pq.emplace(nums[i], i);
        
        // 移除窗口外的元素
        while (pq.top().second <= i - k)
        {
            pq.pop();
        }
        
        if (i >= k - 1)
        {
            res.push_back(pq.top().first);
        }
    }
    
    return res;
}
```

