### 2.1 基本 DFS

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;

void dfs(int start, const vector<vector<int>>& adj)
{
    int n = adj.size();
    vector<bool> visited(n, false);
    stack<int> s;
    
    // 初始化
    s.push(start);
    visited[start] = true;
    
    while (!s.empty())
    {
        int u = s.top();
        s.pop();
        cout << u << " ";  // 处理节点
        
        // 访问邻接点（注意顺序，栈是后进先出，所以反序入栈）
        for (auto it = adj[u].rbegin(); it != adj[u].rend(); ++it)
        {
            int v = *it;
            if (!visited[v])
            {
                visited[v] = true;
                s.push(v);
            }
        }
    }
}

