    adj[1] = {0, 3, 4};
    adj[2] = {0, 5};
    adj[3] = {1};
    adj[4] = {1};
    adj[5] = {2};
    
    cout << "DFS 遍历结果: ";
    dfs(0, adj);  // 0 1 3 4 2 5
    cout << endl;
    
    return 0;
}
