    a.erase(unique(all(a)), a.end());

    // C++11 二分查找
    int x;
    cin >> x;
    auto it = lower_bound(all(a), x);
    if (it != a.end() && *it == x)
    {
        // 找到x
    }

    // C++11 删除元素（O(N)）
    a.erase(remove_if(all(a), [](int v)
    {
        return v < 0;
    }), a.end());

