// 定义一个 trait
trait Summary
{
    // 抽象方法 - 没有默认实现
    fn summarize(&self) -> String;
    
    // 具有默认实现的方法
    fn default_info(&self) -> String
    {
        String::from("这是一个内容摘要")
    }
}

// 定义另一个 trait
trait Display
{
    fn display(&self) -> String;
}

// 定义一个结构体
struct NewsArticle
{
    pub headline: String,
    pub location: String,
    pub author: String,
    pub content: String,
}

// 为结构体实现 trait
impl Summary for NewsArticle
{
    fn summarize(&self) -> String
    {
        format!("{}, by {} ({})", self.headline, self.author, self.location)
    }
}

// 另一个结构体
struct Tweet
{
    pub username: String,
    pub content: String,
    pub reply: bool,
    pub retweet: bool,
}

// 为 Tweet 实现 Summary trait
impl Summary for Tweet
{
    fn summarize(&self) -> String
    {
        format!("{}: {}", self.username, self.content)
    }
}

// 实现 Display trait
impl Display for Tweet
{
    fn display(&self) -> String
    {
        format!("推文 - 用户: {}, 内容: {}", self.username, self.content)
    }
}

// 另一个实现了 Summary 的结构体
struct Article
{
    pub headline: String,
    pub location: String,
    pub author: String,
    pub content: String,
}

impl Summary for Article
{
    fn summarize(&self) -> String
    {
