const STATIC_STR: &'static str = "静态字符串常量";

// 使用生命周期来避免悬垂引用的示例
fn avoid_dangling_reference() -> String
{
    // 以下代码会导致编译错误，因为试图返回局部变量的引用
    /*
    fn dangling() -> &String
    {
        let s = String::from("hello");
        &s  // 错误：返回局部变量的引用
    }
    */
    
    // 正确的做法是返回所有权
    fn no_dangle() -> String
    {
        let s = String::from("hello");
        s  // 返回 String，而不是引用
    }
    
    no_dangle()
