    println!("flatten: {:?}", flat);
    
    // 2.5 复杂迭代器链
    println!("\n2.5 复杂迭代器链示例");
    println!("--------------------");
    
    let data = vec![
        ("Alice", 25),
        ("Bob", 30),
        ("Carol", 22),
        ("David", 35),
        ("Eve", 28),
