### 2.2.8 完整的 TCP 服务端流程

#### 服务端开发流程：

1. 创建`socket`,返回一个文件描述符`lfd` -- ``socket()` --该文件描述符用于监听客户端连接

2. 将`lfd`和`IP PORT`进行绑定 -- `bind()`

3. 将`lfd`由主动变为被动监听 -- `listen()`

4. 接受一个新的连接,得到一个文件描述符`cfd` -- `accept()` -- 该文件描述符是用于和客户端进行通信的

5. while(1)
{
    接收数据 -- `read`或者`recv`
    发送数据 -- `write`或者`send`
}

6. 关闭文件描述符 -- `close(lfd)`和`close(cfd)`

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

int main()
{
    // 1. 创建socket，返回监听文件描述符 lfd
    int lfd = socket(AF_INET, SOCK_STREAM, 0);
    if (lfd < 0)
    {
        perror("socket error");
        return -1;
    }

    // 2. 将 lfd 和 IP、PORT 进行绑定
    struct sockaddr_in serv;
    bzero(&serv, sizeof(serv));
    serv.sin_family = AF_INET;
    serv.sin_port = htons(8888);
    serv.sin_addr.s_addr = htonl(INADDR_ANY);  // 绑定本地任意可用IP

    if (bind(lfd, (struct sockaddr*)&serv, sizeof(serv)) < 0)
    {
        perror("bind error");
        close(lfd);
        return -1;
    }

    // 3. 将 lfd 由主动变为被动监听
    if (listen(lfd, 128) < 0)
    {
        perror("listen error");
        close(lfd);
        return -1;
    }

    // 4. 接受新连接，得到通信文件描述符 cfd
    struct sockaddr_in client;
    socklen_t len = sizeof(client);
    int cfd = accept(lfd, (struct sockaddr*)&client, &len);
    if (cfd < 0)
    {
        perror("accept error");
        close(lfd);
        return -1;
    }

    // 5. 循环处理客户端请求
    int n = 0;
    char buf[1024];
    while (1)
    {
        // 接收数据
        memset(buf, 0x00, sizeof(buf));
        n = read(cfd, buf, sizeof(buf));
        if (n <= 0)
        {
            printf("read error or client closed\n");
            break;
        }
        printf("n=[%d], buf=[%s]\n", n, buf);

        // 处理数据：转换为大写
        for (int i = 0; i < n; i++)
        {
            buf[i] = toupper(buf[i]);
        }

        // 发送响应
        write(cfd, buf, n);
    }

    // 6. 关闭文件描述符
    close(cfd);
    close(lfd);

    return 0;
}
```

