### 4. 单调队列 (滑动窗口最值)
*   **什么时候使用**：在一个固定大小为 $k$ 的滑动窗口内，随着窗口向右移动，频繁查询窗口内的最大值或最小值；或用于优化 1D 动态规划转移（单调队列优化DP）。
*   **限制条件**：滑动窗口的边界必须是单调向右移动的，且查询的范围大小固定。
*   **时间复杂度**：每个元素最多进队一次、出队一次，均摊复杂度 $O(N)$。

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;

// 滑动窗口最值：求大小为 k 的窗口内最小值
vector<int> minSlidingWindow(vector<int>& nums, int k)
{
    int n = nums.size();
    deque<int> dq; // 存储元素下标
    vector<int> res;

    for (int i = 0; i < n; i++)
    {
        // 1. 移除超出当前滑动窗口左边界的下标
        if (!dq.empty() && dq.front() < i - k + 1)
        {
            dq.pop_front();
        }
        // 2. 保持队列中下标对应的值单调递增（求最小值用 >，求最大值用 <）
        while (!dq.empty() && nums[dq.back()] > nums[i])
        {
            dq.pop_back();
        }
        dq.push_back(i);

        // 3. 当窗口大小达到 k 时，队头元素对应的就是当前窗口的最值
        if (i >= k - 1)
        {
            res.push_back(nums[dq.front()]);
        }
    }
    return res;
}

signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr); cout.tie(nullptr);

    return 0;
}
```

