### 5. Kruskal 最小生成树 (MST)
*   **什么时候使用**：给定一个无向带权图，求一个连接所有节点的树，且该树的边权总和最小。
*   **限制条件**：不能直接用于有权有向图的最小生成树（那是朱-刘算法）。
*   **时间复杂度**：$O(M \log M)$（其中 $M$ 为边数），性能瓶颈在于边权排序，极易编写。

```cpp
#include <bits/stdc++.h>
#define endl '\n'
#define int long long
using namespace std;

struct Edge
{
    int u, v, w;
    bool operator<(const Edge& other) const
    {
        return w < other.w;
    }
};

struct DSU
{
    vector<int> parent;
    DSU(int n)
    {
        parent.resize(n + 1);
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int i)
    {
        if (parent[i] == i)
        {
            return i;
        }
        return parent[i] = find(parent[i]);
    }
    bool unite(int i, int j)
    {
        int root_i = find(i);
        int root_j = find(j);
        if (root_i != root_j)
        {
            parent[root_i] = root_j;
            return true;
        }
        return false;
    }
};

// 返回：{最小生成树权值和, 实际加入的边数}。若 边数 != n - 1 则代表图不连通
pair<int, int> kruskal(int n, vector<Edge>& edges)
{
    sort(edges.begin(), edges.end());
    DSU dsu(n);
    int mst_weight = 0;
    int edge_count = 0;

    for (auto& edge : edges)
    {
        if (dsu.unite(edge.u, edge.v))
        {
            mst_weight += edge.w;
            edge_count++;
            if (edge_count == n - 1)
            {
                break;
            }
        }
    }
    return {mst_weight, edge_count};
}

signed main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr); cout.tie(nullptr);

    return 0;
}
```

