	for (int i = 0; i < (1 << n); i++)  // i 代表一种具体的选择方案
	{
	    // 遍历这 n 个物品，看看当前方案 i 里面，选中了哪些物品
	    for (int j = 0; j < n; j++)
		{ 
	        // 核心位运算：检查数字 i 的二进制第 j 位是否为 1
	        // (1 << j) 意思是把 1 左移 j 位。例如 j=2 时，就是 00100
	        if (i & (1 << j))
			{
	            // 如果结果不为 0，说明第 j 个物品被选中了！(注意 j 是从 0 开始的)

	            // 在这里写选中后的处理逻辑...
	        }
	    }
	}
	return 0; 
} 
